import urllib.request, json, os, base64

token = os.environ.get("GITHUB_TOKEN","")
repo  = "dperuffo/estudo-de-rede"

# sobre-en.html
_b64_sobre_en = ""
_content_sobre_en = base64.b64decode(_b64_sobre_en.encode())
_url_sobre_en = f"https://api.github.com/repos/{repo}/contents/landing/sobre-en.html"
_req_sobre_en = urllib.request.Request(_url_sobre_en, headers={"Authorization": "token " + token, "Accept": "application/vnd.github.v3+json"})
_sha_sobre_en = None
try:
    with urllib.request.urlopen(_req_sobre_en) as r: _sha_sobre_en = json.loads(r.read()).get("sha")
except: pass
_payload_sobre_en = {"message": "feat: pagina EN sobre-en.html", "content": base64.b64encode(_content_sobre_en).decode()}
if _sha_sobre_en: _payload_sobre_en["sha"] = _sha_sobre_en
_req2_sobre_en = urllib.request.Request(_url_sobre_en, data=json.dumps(_payload_sobre_en).encode(), method="PUT", headers={"Authorization": "token " + token, "Content-Type": "application/json", "Accept": "application/vnd.github.v3+json"})
with urllib.request.urlopen(_req2_sobre_en) as r:
    print(f"GITHUB OK sobre-en.html: commit {json.loads(r.read())['commit']['sha'][:7]}")

